#!/bin/bash
# This script copy the .phy files from clustering 0.85 analysis in a new directory to IQTree analysis. 

# Create directory for IQ-TREE input files
# -p ensures no error is thrown if the directory already exists
mkdir -p ../results/ipyrad/iqtree/input

# Copy all .phy files generated by ipyrad into the IQ-TREE input directory
# The directory structure assumes multiple clustering thresholds inside 'Combined'
# (e.g., clust85, clust90, etc.), each containing an *_outfiles directory
#
# Exclude the file 'nout_clust90.phy' from being copied
find ../ipyrad/Combined/ -type f -name "*.phy" ! -name "nout_clust90.phy" \
    -exec cp {} ../results/ipyrad/iqtree/input/ \;
